diff --git a/libm/machine/riscv/test/test_cosf.c b/libm/machine/riscv/test/test_cosf.c
index 1852df949..cf9b98785 100644
--- a/libm/machine/riscv/test/test_cosf.c
+++ b/libm/machine/riscv/test/test_cosf.c
@@ -1,5 +1,10 @@
 /*
  * cosf() test harness — prints (input_hex, output_hex) pairs.
+ *
+ * Build two versions:
+ *   1. Linked with optimized Andes assembly cosf  (test_cosf_opt.elf)
+ *   2. Linked with toolchain's default cosf        (test_cosf_ref.elf)
+ * Run both, diff the output to find discrepancies.
  */

 #include <math.h>
@@ -27,28 +32,156 @@ static void emit(float x)
     printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
 }

-int main(void)
+static void emit_u(uint32_t bits)
+{
+    emit(u2f(bits));
+}
+
+/* ------------------------------------------------------------------ */
+/* Test points                                                         */
+/* ------------------------------------------------------------------ */
+
+/* 1. Special values */
+static void test_special(void)
+{
+    /* Zeros */
+    emit(0.0f);
+    emit(-0.0f);
+
+    /* NaN */
+    emit_u(0x7fc00000u); /* qNaN */
+    emit_u(0x7f800001u); /* sNaN */
+    emit_u(0xffc00000u); /* -NaN */
+
+    /* Infinity */
+    emit_u(0x7f800000u); /* +Inf */
+    emit_u(0xff800000u); /* -Inf */
+}
+
+/* 2. Tiny values: cos(x) ~ 1 */
+static void test_tiny(void)
 {
-    /* specials */
-    emit(0.0f); emit(-0.0f);
-    emit(u2f(0x7fc00000u)); emit(u2f(0x7f800000u)); emit(u2f(0xff800000u));
-    emit(u2f(0x00000001u)); emit(u2f(0x80000001u)); emit(u2f(0x007fffffu));
+    emit_u(0x00000001u); /* min denorm */
+    emit_u(0x80000001u);
+    emit_u(0x00400000u); /* mid denorm */
+    emit_u(0x80400000u);
+    emit_u(0x007fffffu); /* max denorm */
+    emit_u(0x807fffffu);
+    emit(FLT_MIN);

